        self.name = name
    def speak(self):
        return f'{self.name} makes a sound'

class Dog(Animal):
    def __init__(self, name, breed):
        super().__init__(name)
        self.breed = breed
    def speak(self):
        return f'{self.name} barks: Woof!'

class Cat(Animal):
    def speak(self):
        return f'{self.name} meows: Meow!'

