fibonacci_exp.code:
def fib_recursive(n):
    if n <= 1: return n
    return fib_recursive(n-1) + fib_recursive(n-2)

def fib_iterative(n):
    a, b = 0, 1
    result = []
    for _ in range(n):
        result.append(a)
        a, b = b, a+b
    return result

def fib_generator(limit):
    a, b = 0, 1
    while a < limit:
        yield a
        a, b = b, a+b

print([fib_recursive(i) for i in range(10)])
print(fib_iterative(10))
print(list(fib_generator(100)))

